import React from "react";

/**
 * AnaSayfa — Dark + Modern + Animasyon Odaklı
 * - Harici paket yok (sadece React)
 * - Veri olmasa da sürekli hareketli bir yüzey
 * - Erişilebilirlik: prefers-reduced-motion desteği
 */

export default function AnaSayfa({
    // İstersen bu prop'ları geçebilirsin; geçmezsen animasyonlu placeholder'lar görünür.
    loading = true,
    kpi, // { bugunTalep, bekleyenTeslimat, buAyGelir, buAyGider }
    hareketler = [],
    talepler = [],
    onYeniGelir,
    onYeniGider,
    onYeniTalep,
    onYeniTedarik,
    onTumTalepler,
}) {
    const hasKpi = Boolean(kpi);
    const hasHareket = hareketler?.length > 0;
    const hasTalep = talepler?.length > 0;

    return (
        <div className="anim-root">
            <style>{`
        :root{
          --bg0:#0b0d12; --bg1:#0e121a; --text:#e8ecf8; --muted:#9aa6c3; --line:#1d2435;
          --brandA:#6c7cff; --brandB:#9a7bff; --brandC:#22c55e;
          --panelTop:#0f1423; --panelBot:#0c1220;
        }
        @media (prefers-color-scheme: dark){ :root{ color-scheme:dark; } }

        /* --------- Layout / Theme --------- */
        .anim-root{
          min-height:100dvh; color:var(--text);
          background:
            radial-gradient(100rem 50rem at -5% -10%, rgba(108,124,255,.15), transparent 50%),
            radial-gradient(70rem 40rem at 120% 0%, rgba(34,197,94,.10), transparent 60%),
            linear-gradient(180deg, var(--bg0) 0%, var(--bg1) 60%, var(--bg0) 100%);
          overflow-x:hidden;
        }
        .container{ max-width:1200px; margin:0 auto; padding:20px; }

        /* --------- Topbar --------- */
        .top{ position:sticky; top:0; z-index:20; border-bottom:1px solid var(--line);
              backdrop-filter:saturate(1.1) blur(12px); background:rgba(12,15,22,.55); }
        .top-in{ display:flex; align-items:center; justify-content:space-between; gap:16px; padding:10px 20px; }
        .brand{ display:flex; align-items:center; gap:10px; font-weight:800; letter-spacing:.2px; }
        .nav{ display:flex; gap:12px; }
        .nav a{ color:#cbd3ea; text-decoration:none; padding:8px 12px; border-radius:12px; }
        .nav a:hover{ background:#171c2b; }

        /* --------- Panels --------- */
        .panel{ background:linear-gradient(180deg, var(--panelTop) 0%, var(--panelBot) 100%);
                border:1px solid var(--line); border-radius:18px; box-shadow:0 16px 40px rgba(0,0,0,.35); }
        .p16{ padding:16px; }
        .hero{ display:grid; grid-template-columns:1.1fr .9fr; gap:18px; margin:18px auto; }
        @media(max-width:960px){ .hero{ grid-template-columns:1fr; } }

        /* --------- Entrance Animations --------- */
        .fade-up{ opacity:0; transform:translateY(12px); animation:fadeUp .5s ease forwards; }
        .fade-up.d2{ animation-delay:.08s; }
        .fade-up.d3{ animation-delay:.16s; }
        .fade-up.d4{ animation-delay:.24s; }
        @keyframes fadeUp { to{ opacity:1; transform:none; } }

        /* --------- Title / Gradient Flow --------- */
        .title{ font-size:32px; font-weight:900; margin:0; letter-spacing:-.02em; }
        .flow{
          background: linear-gradient(90deg, var(--brandA), var(--brandB), var(--brandC), var(--brandA));
          background-size: 300% 100%;
          -webkit-background-clip: text; background-clip: text; color:transparent;
          animation:flow 8s linear infinite;
        }
        @keyframes flow{ 0%{background-position:0% 50%} 100%{background-position:300% 50%} }
        .sub{ color:var(--muted); margin:6px 0 0; }

        /* --------- Buttons with ripple --------- */
        .actions{ display:flex; flex-wrap:wrap; gap:10px; margin-top:14px; }
        .btn{
          position:relative; overflow:hidden;
          border:1px solid var(--line); background:#0e1424; color:#dfe6ff;
          padding:10px 14px; border-radius:14px; font-weight:800; cursor:pointer;
          transition:transform .15s ease, box-shadow .15s ease;
          box-shadow:0 0 0 0 rgba(108,124,255,.0);
        }
        .btn.primary{
          background:linear-gradient(90deg, var(--brandA), var(--brandB));
          color:#0b0d12; border-color:#2a3350;
          box-shadow:0 10px 24px rgba(108,124,255,.22);
        }
        .btn:hover{ transform:translateY(-1px); }
        .btn:disabled{ opacity:.6; cursor:not-allowed; }
        .btn::after{
          content:""; position:absolute; inset:0; transform:scale(0);
          background:radial-gradient(120px 50px at var(--mx,50%) var(--my,50%), rgba(255,255,255,.18), transparent 60%);
          transition:transform .25s ease;
        }
        .btn:hover::after{ transform:scale(1); }

        /* --------- KPI + Shimmer --------- */
        .kpis{ display:grid; grid-template-columns:repeat(4,1fr); gap:12px; margin-top:12px; }
        @media(max-width:900px){ .kpis{ grid-template-columns:repeat(2,1fr); } }
        .kpi{ background:#0e1424; border:1px solid var(--line); border-radius:14px; padding:12px; position:relative; overflow:hidden; }
        .kpi h4{ font-size:12px; color:#9aa3bf; margin:0 0 6px; font-weight:800; letter-spacing:.02em; }
        .kpi strong{ font-size:22px; }

        .shimmer{ position:relative; overflow:hidden; background:#121a2c; border-radius:10px; }
        .shimmer::after{ content:""; position:absolute; inset:0; transform:translateX(-100%);
          background:linear-gradient(90deg, transparent, rgba(255,255,255,.10), transparent);
          animation:sh 1.4s infinite; }
        @keyframes sh{ 100%{ transform:translateX(100%);} }

        /* --------- Dashboard Bars --------- */
        .bars{ display:flex; align-items:flex-end; gap:8px; height:170px; padding:12px; border:1px dashed #1f2940; border-radius:12px; }
        .bar{ width:10%; min-width:14px; background:linear-gradient(180deg, #6c7cff33, #6c7cff88); border-radius:6px;
              animation:grow 2.4s ease-in-out infinite; }
        .bar:nth-child(odd){ animation-delay:.32s; }
        .bar:nth-child(3n){ animation-delay:.64s; }
        @keyframes grow{ 0%,100%{ height:22%; } 50%{ height:88%; } }

        /* --------- Tables / Skeleton Rows --------- */
        .grid{ display:grid; grid-template-columns:1.1fr .9fr; gap:18px; margin-top:18px; }
        @media(max-width:1000px){ .grid{ grid-template-columns:1fr; } }
        .table{ width:100%; border-collapse:collapse; font-size:14px; }
        .table th, .table td{ padding:10px 12px; border-bottom:1px solid var(--line); text-align:left; }
        .table thead th{ font-size:12px; color:#8d98b8; text-transform:uppercase; background:#0f1628; }
        .empty{ color:#8a93ad; padding:14px; text-align:center; }

        /* --------- FX Background Blobs --------- */
        .fx{ position:absolute; inset:-20vh -20vw; z-index:-1; pointer-events:none; opacity:.35; }
        .blob{ position:absolute; width:36rem; height:36rem; filter:blur(80px);
               background:conic-gradient(from 90deg, #253051, #1a243f, #253051); border-radius:50%;
               animation:float 16s ease-in-out infinite; mix-blend:screen; }
        .blob.b2{ left:70%; top:-10%; width:28rem; height:28rem; animation-delay:-6s; }
        .blob.b3{ left:20%; top:60%; width:34rem; height:34rem; animation-delay:-11s; }
        @keyframes float{ 0%,100%{ transform:translateY(0) rotate(0deg);} 50%{ transform:translateY(16px) rotate(10deg);} }

        /* --------- Reduced motion --------- */
        @media (prefers-reduced-motion: reduce){
          .fade-up{ animation:none; opacity:1; transform:none; }
          .bar{ animation:none; height:60%; }
          .shimmer::after{ animation:none; }
          .blob{ animation:none; }
          .btn::after{ display:none; }
        }
      `}</style>

            {/* Animated background blobs */}
            <div className="fx" aria-hidden>
                <div className="blob" />
                <div className="blob b2" />
                <div className="blob b3" />
            </div>

            {/* TOP */}
            <div className="top">
                <div className="top-in container fade-up">
                    <div className="brand">{Logo()} Lojistik Portal</div>
                    <nav className="nav" aria-label="primary">
                        <a href="#gelirgider">Gelir-Gider</a>
                        <a href="#talep">Talepler</a>
                        <a href="#tedarik">Tedarik</a>
                        <a href="#dashboard">Dashboard</a>
                    </nav>
                </div>
            </div>

            {/* HERO */}
            <main className="container">
                <section className="hero">
                    <div className="panel p16 fade-up d2">
                        <h1 className="title">Operasyon <span className="flow">Özetiniz</span></h1>
                        <p className="sub">Gelir-gider, talep-tedarik ve teslimatlar.</p>

                        <div
                            className="actions"
                            role="group"
                            onMouseMove={(e) => {
                                const t = e.target.closest(".btn");
                                if (!t) return;
                                const rect = t.getBoundingClientRect();
                                t.style.setProperty("--mx", `${e.clientX - rect.left}px`);
                                t.style.setProperty("--my", `${e.clientY - rect.top}px`);
                            }}
                        >
                            <button className="btn primary" onClick={onYeniGelir} disabled={!onYeniGelir}>Yeni Gelir</button>
                            <button className="btn" onClick={onYeniGider} disabled={!onYeniGider}>Yeni Gider</button>
                            <button className="btn" onClick={onYeniTalep} disabled={!onYeniTalep}>Talep Oluştur</button>
                            <button className="btn" onClick={onYeniTedarik} disabled={!onYeniTedarik}>Tedarik Kaydı</button>
                        </div>

                        {/* KPI — veri yoksa bile animasyonlu shimmer */}
                        <div className="kpis">
                            <div className="kpi"><h4>Bugünkü Talepler</h4>{hasKpi ? <strong>{kpi.bugunTalep}</strong> : <div className="shimmer" style={{ height: 22 }} />}</div>
                            <div className="kpi"><h4>Bekleyen Teslimat</h4>{hasKpi ? <strong>{kpi.bekleyenTeslimat}</strong> : <div className="shimmer" style={{ height: 22 }} />}</div>
                            <div className="kpi"><h4>Bu Ay Gelir</h4>{hasKpi ? <strong>{formatTL(kpi.buAyGelir)}</strong> : <div className="shimmer" style={{ height: 22 }} />}</div>
                            <div className="kpi"><h4>Bu Ay Gider</h4>{hasKpi ? <strong>{formatTL(kpi.buAyGider)}</strong> : <div className="shimmer" style={{ height: 22 }} />}</div>
                        </div>
                    </div>

                    {/* Dashboard: sürekli animasyonlu barlar (placeholder) */}
                    <div className="panel p16 fade-up d3" id="dashboard">
                        <div className="bars" aria-label="Animasyonlu grafik yer tutucu">
                            {Array.from({ length: 10 }).map((_, i) => <div key={i} className="bar" />)}
                        </div>
                    </div>
                </section>

                {/* TABLOLAR – veri yoksa animasyonlu iskelet satırlar */}
                <section className="grid">
                    <div className="panel p16 fade-up d3" id="gelirgider">
                        <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
                            <h3 style={{ margin: 0 }}>Son Gelir-Gider Hareketleri</h3>
                            <div style={{ display: 'flex', gap: 8 }}>
                                <button className="btn" onClick={onYeniGelir} disabled={!onYeniGelir}>Gelir</button>
                                <button className="btn" onClick={onYeniGider} disabled={!onYeniGider}>Gider</button>
                            </div>
                        </div>
                        {loading || !hasHareket ? (
                            <SkeletonRows rows={4} cols={5} />
                        ) : (
                            <table className="table">
                                <thead><tr><th>Tarih</th><th>Tür</th><th>Açıklama</th><th>Tutar</th><th>Durum</th></tr></thead>
                                <tbody>{hareketler.map((r, i) => (
                                    <tr key={i}><td>{r.tarih}</td><td>{r.tur}</td><td>{r.aciklama}</td><td>{formatTL(r.tutar)}</td><td>{r.durum}</td></tr>
                                ))}</tbody>
                            </table>
                        )}
                    </div>

                    <div className="panel p16 fade-up d4" id="talep">
                        <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
                            <h3 style={{ margin: 0 }}>Aktif Talepler / Tedarik</h3>
                            <button className="btn" onClick={onTumTalepler} disabled={!onTumTalepler}>Tüm Talepler</button>
                        </div>
                        {loading || !hasTalep ? (
                            <SkeletonRows rows={4} cols={5} />
                        ) : (
                            <table className="table">
                                <thead><tr><th>Talep No</th><th>Müşteri</th><th>Çıkış → Varış</th><th>Kapasite</th><th>Durum</th></tr></thead>
                                <tbody>{talepler.map((t, i) => (
                                    <tr key={i}><td>{t.no}</td><td>{t.musteri}</td><td>{t.rota}</td><td>{t.kapasite}</td><td>{t.durum}</td></tr>
                                ))}</tbody>
                            </table>
                        )}
                    </div>
                </section>
            </main>

            <footer className="container" style={{ color: "#8a93ad" }}>© {new Date().getFullYear()} Lojistik Portal</footer>
        </div>
    );
}

/* ---------- Helpers ---------- */
function formatTL(n) { if (n == null) return "—"; try { return n.toLocaleString('tr-TR', { style: 'currency', currency: 'TRY' }); } catch { return `${n} ₺`; } }

function SkeletonRows({ rows = 4, cols = 5 }) {
    return (
        <div>
            {Array.from({ length: rows }).map((_, ri) => (
                <div key={ri} style={{ display: 'grid', gridTemplateColumns: `repeat(${cols},1fr)`, gap: 10, marginBottom: 10 }}>
                    {Array.from({ length: cols }).map((_, ci) => (
                        <div key={ci} className="shimmer" style={{ height: 30, borderRadius: 10 }} />
                    ))}
                </div>
            ))}
        </div>
    );
}

/* ---------- Logo ---------- */
function Logo() {
    return (
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="url(#g)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden>
            <defs>
                <linearGradient id="g" x1="0" y1="0" x2="1" y2="1">
                    <stop offset="0%" stopColor="var(--brandA)" />
                    <stop offset="100%" stopColor="var(--brandC)" />
                </linearGradient>
            </defs>
            <rect x="3" y="3" width="18" height="18" rx="5" />
            <path d="M7 12h10M7 8h6M7 16h8" />
        </svg>
    );
}
